"""
memory_map.py — Sidecar Registry: ChunkRegistry + GroupRegistry

SIDECAR DESIGN CONSTRAINT
--------------------------
The source vector database is strictly read-only.  This module owns all
mutable state: phase angles, recency, co-activation counts, and the live
Group Vectors (behavioural centroids).  Everything lives in RAM during
execution and is only flushed to disk during explicit sleep-cycle checkpoints.

Two-level memory hierarchy
---------------------------
ChunkRegistry  chunk_id → { φ, last_access, phase_velocity, co_activations }
GroupRegistry  group_id → { group_vector (np.ndarray 2N), member_ids,
                             φ, last_access, co_activations }

Group vectors are stored as flat 2N float32 arrays (real lane ‖ imag lane),
matching the ONNX engine's tensor geometry exactly.

Persistence
-----------
  DEV:        SQLite  sidecar  (local file, zero external deps)
  PRODUCTION: pgvector         (native vector type, ANN-searchable)
              → swap via PersistenceBackend protocol (see bottom of file)
"""

from __future__ import annotations

import heapq
import math
import sqlite3
import threading
import time
from collections import defaultdict
from dataclasses import dataclass, field
from pathlib import Path
from typing import Dict, List, Optional, Set, Tuple

import numpy as np

from .frequency import FrequencyFamily


# ─────────────────────────────────────────────────────────────────────────────
# Chunk metadata
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class ChunkMeta:
    """All sidecar state for a single source chunk."""
    phi: float = FrequencyFamily.NEUTRAL.value
    last_access: float = field(default_factory=time.time)
    phase_velocity: float = 0.0          # Δφ/Δt — how fast context is shifting
    group_id: Optional[str] = None       # which group this chunk belongs to
    _prev_phi: float = field(default=0.0,            repr=False)
    _prev_ts:  float = field(default_factory=time.time, repr=False)

    def update_phase(self, new_phi: float) -> None:
        now = time.time()
        dt  = now - self._prev_ts
        if dt > 1e-6:
            self.phase_velocity = (new_phi - self._prev_phi) / dt
        self._prev_phi = self.phi
        self._prev_ts  = now
        self.phi = new_phi

    def touch(self) -> None:
        self.last_access = time.time()

    def staleness(self) -> float:
        return time.time() - self.last_access


# ─────────────────────────────────────────────────────────────────────────────
# Group metadata
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class GroupMeta:
    """
    A dynamic Group Vector — behavioural centroid of its member chunks.

    group_vector is a flat float32 array of shape (2N,):
      [0:N]  → real lane  = mean(A_i · cos(φ_i))
      [N:2N] → imag lane  = mean(A_i · sin(φ_i))

    This is recomputed by the sleep cycle whenever membership changes.
    """
    group_id: str
    phi: float = FrequencyFamily.NEUTRAL.value
    last_access: float = field(default_factory=time.time)
    member_ids: Set[str] = field(default_factory=set)
    group_vector: Optional[np.ndarray] = None   # shape (2N,) float32
    # co-activation with other groups
    co_activations: Dict[str, int] = field(default_factory=dict)

    def touch(self) -> None:
        self.last_access = time.time()

    def staleness(self) -> float:
        return time.time() - self.last_access

    def recompute_vector(
        self,
        chunk_amplitudes: Dict[str, np.ndarray],
        chunk_phis: Dict[str, float],
    ) -> None:
        """
        Recompute the group centroid from current member amplitudes and phases.

        Parameters
        ----------
        chunk_amplitudes : chunk_id → amplitude vector (N,)
        chunk_phis       : chunk_id → phase angle float
        """
        members = [cid for cid in self.member_ids
                   if cid in chunk_amplitudes and cid in chunk_phis]
        if not members:
            self.group_vector = None
            return

        N = len(next(iter(chunk_amplitudes.values())))
        real_sum = np.zeros(N, dtype=np.float32)
        imag_sum = np.zeros(N, dtype=np.float32)

        for cid in members:
            A   = chunk_amplitudes[cid]
            phi = chunk_phis[cid]
            real_sum += A * math.cos(phi)
            imag_sum += A * math.sin(phi)

        M = len(members)
        self.group_vector = np.concatenate([
            real_sum / M,
            imag_sum / M,
        ]).astype(np.float32)


# ─────────────────────────────────────────────────────────────────────────────
# Registry
# ─────────────────────────────────────────────────────────────────────────────

class ResonanceRegistry:
    """
    Volatile in-RAM sidecar registry — the single source of truth for
    all phase, recency, co-activation, and group-vector state during
    live agent execution.

    The upstream source DB is never consulted or mutated by this class.
    All public mutating methods are protected by an RLock for thread safety.
    """

    def __init__(self) -> None:
        self._chunks: Dict[str, ChunkMeta] = {}
        self._groups: Dict[str, GroupMeta] = {}

        # chunk-level co-activation  (id_a, id_b) → count  (id_a < id_b)
        self._chunk_coact: Dict[Tuple[str, str], int] = defaultdict(int)

        # amplitudes cache  chunk_id → np.ndarray (N,)
        # populated by surf_and_flag; used by GroupMeta.recompute_vector.
        # NOT persisted to sidecar — source DB is the authority for vectors.
        self._amplitudes: Dict[str, np.ndarray] = {}

        # Most Recent Index — max-heap of (-last_access, chunk_id).
        # Kept in sync by surf_and_flag and record_access.
        # Entries may be stale (lazy deletion); most_recent() filters them.
        self._recency_heap: List[Tuple[float, str]] = []

        # Groups whose membership changed since the last recompute_group_vector
        # call.  Sleep cycle uses this to skip unchanged groups.
        self._dirty_groups: Set[str] = set()

        # session state
        self._active_phase: float = FrequencyFamily.NEUTRAL.value

        # thread safety — RLock allows re-entrant acquisition from same thread
        self._lock = threading.RLock()

    # ── Session state ─────────────────────────────────────────────────────

    @property
    def active_phase(self) -> float:
        return self._active_phase

    def set_active_frequency(self, family: FrequencyFamily | float) -> None:
        """Broadcast a new operational frequency to the session."""
        with self._lock:
            self._active_phase = float(family)

    # ── Chunk ingestion ───────────────────────────────────────────────────

    def surf_and_flag(
        self,
        chunk_id: str,
        amplitude: np.ndarray,
        active_phase: Optional[float] = None,
        parent_id: Optional[str] = None,
        group_id: Optional[str] = None,
    ) -> ChunkMeta:
        """
        Called immediately when a new chunk enters the system.

        1. Snaps φ to active operational frequency.
        2. Caches the amplitude vector for group centroid computation.
        3. Assigns the chunk to an existing or new group.
        4. Initialises Most Recent timestamp.
        5. Couples to parent trigger chunk in Most Related index.
        """
        with self._lock:
            snap_phi = active_phase if active_phase is not None else self._active_phase

            now  = time.time()
            meta = ChunkMeta(phi=snap_phi, last_access=now)
            meta._prev_phi = snap_phi
            self._chunks[chunk_id] = meta

            self._amplitudes[chunk_id] = amplitude.astype(np.float32)

            # Most Recent Index: push onto max-heap (negate for max semantics)
            heapq.heappush(self._recency_heap, (-now, chunk_id))

            resolved_gid = group_id or self._phase_to_group_id(snap_phi)
            meta.group_id = resolved_gid
            self._ensure_group(resolved_gid, snap_phi)
            self._groups[resolved_gid].member_ids.add(chunk_id)
            self._dirty_groups.add(resolved_gid)

            if parent_id and parent_id in self._chunks:
                self._record_chunk_coact(chunk_id, parent_id)

            return meta

    def _phase_to_group_id(self, phi: float) -> str:
        """Default group assignment: nearest FrequencyFamily name."""
        return FrequencyFamily.nearest(phi).name

    def _ensure_group(self, group_id: str, phi: float) -> GroupMeta:
        if group_id not in self._groups:
            self._groups[group_id] = GroupMeta(group_id=group_id, phi=phi)
        return self._groups[group_id]

    # ── Access & co-activation tracking ──────────────────────────────────

    def record_access(self, chunk_id: str) -> None:
        """Update Most Recent Index for a retrieved chunk and its group."""
        with self._lock:
            if chunk_id in self._chunks:
                meta = self._chunks[chunk_id]
                meta.touch()
                # Push updated timestamp; stale entries are skipped lazily in most_recent()
                heapq.heappush(self._recency_heap, (-meta.last_access, chunk_id))
                gid = meta.group_id
                if gid and gid in self._groups:
                    self._groups[gid].touch()

    def record_co_activation(self, id_a: str, id_b: str) -> None:
        """Increment co-activation weight between two chunks."""
        with self._lock:
            self._record_chunk_coact(id_a, id_b)
            ga = self._chunks.get(id_a, ChunkMeta()).group_id
            gb = self._chunks.get(id_b, ChunkMeta()).group_id
            if ga and gb and ga != gb:
                grp = self._groups.get(ga)
                if grp:
                    grp.co_activations[gb] = grp.co_activations.get(gb, 0) + 1

    def _record_chunk_coact(self, id_a: str, id_b: str) -> None:
        key = (min(id_a, id_b), max(id_a, id_b))
        self._chunk_coact[key] += 1

    # ── Phase management ──────────────────────────────────────────────────

    def get_phi(self, chunk_id: str) -> float:
        return self._chunks[chunk_id].phi if chunk_id in self._chunks else 0.0

    def get_phis_batch(self, chunk_ids: List[str]) -> np.ndarray:
        """Return phase angles for a list of chunk IDs as a float32 array."""
        return np.array([self.get_phi(cid) for cid in chunk_ids], dtype=np.float32)

    def set_phi(self, chunk_id: str, phi: float) -> None:
        with self._lock:
            if chunk_id in self._chunks:
                self._chunks[chunk_id].update_phase(phi)

    # ── Group management ──────────────────────────────────────────────────

    def get_group(self, group_id: str) -> Optional[GroupMeta]:
        return self._groups.get(group_id)

    def all_groups(self) -> Dict[str, GroupMeta]:
        return dict(self._groups)

    def recompute_group_vector(self, group_id: str) -> None:
        """Recompute the group centroid from current member state."""
        grp = self._groups.get(group_id)
        if grp is None:
            return
        chunk_phis = {cid: self.get_phi(cid) for cid in grp.member_ids}
        grp.recompute_vector(self._amplitudes, chunk_phis)
        self._dirty_groups.discard(group_id)

    def recompute_dirty_groups(self) -> int:
        """
        Recompute group centroids ONLY for groups whose membership or phase
        changed since the last recompute.  Returns count of groups updated.

        This is the incremental version used by the sleep cycle — unchanged
        groups are skipped entirely, making the cycle O(changed) not O(all).
        """
        with self._lock:
            dirty = list(self._dirty_groups)
        for gid in dirty:
            self.recompute_group_vector(gid)
        return len(dirty)

    def add_chunk_to_group(self, chunk_id: str, group_id: str) -> None:
        """Move a chunk into a group and update its ChunkMeta."""
        with self._lock:
            self._ensure_group(group_id, self._active_phase)
            old_gid = self._chunks[chunk_id].group_id if chunk_id in self._chunks else None
            if old_gid and old_gid in self._groups:
                self._groups[old_gid].member_ids.discard(chunk_id)
                self._dirty_groups.add(old_gid)
            self._groups[group_id].member_ids.add(chunk_id)
            self._dirty_groups.add(group_id)
            if chunk_id in self._chunks:
                self._chunks[chunk_id].group_id = group_id

    def evict_chunk_from_group(self, chunk_id: str, group_id: str) -> None:
        """Remove a chunk from a group (chunk remains in ChunkRegistry)."""
        with self._lock:
            grp = self._groups.get(group_id)
            if grp:
                grp.member_ids.discard(chunk_id)
                self._dirty_groups.add(group_id)

    def get_all_group_vectors(self) -> Tuple[List[str], np.ndarray]:
        """
        Return (group_ids, matrix) for all groups with computed vectors.
        matrix shape: (G, 2N) float32
        """
        ids, vecs = [], []
        for gid, grp in self._groups.items():
            if grp.group_vector is not None:
                ids.append(gid)
                vecs.append(grp.group_vector)
        if not vecs:
            return [], np.empty((0, 0), dtype=np.float32)
        return ids, np.stack(vecs, axis=0)

    # ── Most Recent Index ─────────────────────────────────────────────────

    def most_recent(self, n: int = 10) -> List[Tuple[str, float]]:
        """
        Return the n most recently accessed chunks.

        O(k log H) where k=n and H=heap size — not O(n log n) full sort.
        Stale heap entries (chunk deleted, or superseded by a newer push for
        the same chunk_id) are skipped during traversal.

        Returns
        -------
        List of (chunk_id, last_access_timestamp) sorted newest first.
        """
        with self._lock:
            results: List[Tuple[str, float]] = []
            # Work on a copy so we don't mutate the live heap
            heap = list(self._recency_heap)
            heapq.heapify(heap)
            seen: Set[str] = set()
            while heap and len(results) < n:
                neg_ts, cid = heapq.heappop(heap)
                if cid in seen:
                    continue  # superseded entry
                seen.add(cid)
                meta = self._chunks.get(cid)
                if meta is None:
                    continue  # chunk was deleted
                # Verify timestamp matches (entry might be stale after record_access)
                if abs(meta.last_access - (-neg_ts)) < 1e-6 or meta.last_access >= -neg_ts:
                    results.append((cid, meta.last_access))
            return results

    # ── Most Related Index ────────────────────────────────────────────────

    def most_related(self, chunk_id: str, n: int = 10) -> List[Tuple[str, int]]:
        """
        Return the n chunks most frequently co-activated with chunk_id.

        Returns
        -------
        List of (partner_chunk_id, co_activation_count) sorted highest first.
        """
        with self._lock:
            related: Dict[str, int] = {}
            for (id_a, id_b), count in self._chunk_coact.items():
                if id_a == chunk_id:
                    related[id_b] = related.get(id_b, 0) + count
                elif id_b == chunk_id:
                    related[id_a] = related.get(id_a, 0) + count
            ranked = sorted(related.items(), key=lambda x: x[1], reverse=True)
            return ranked[:n]

    # ── Mutation API (delete / update) ────────────────────────────────────

    def delete_chunk(self, chunk_id: str) -> bool:
        """
        Remove a chunk entirely from the registry.

        Cleans up: ChunkMeta, amplitude cache, group membership,
        and co-activation pairs that reference this chunk.

        Returns True if the chunk existed and was removed, False otherwise.
        """
        with self._lock:
            if chunk_id not in self._chunks:
                return False

            meta = self._chunks.pop(chunk_id)
            self._amplitudes.pop(chunk_id, None)

            # Remove from group membership
            if meta.group_id and meta.group_id in self._groups:
                self._groups[meta.group_id].member_ids.discard(chunk_id)
                self._dirty_groups.add(meta.group_id)

            # Remove co-activation pairs referencing this chunk
            to_delete = [
                key for key in self._chunk_coact
                if key[0] == chunk_id or key[1] == chunk_id
            ]
            for key in to_delete:
                del self._chunk_coact[key]

            return True

    def update_chunk(
        self,
        chunk_id: str,
        new_amplitude: Optional[np.ndarray] = None,
        new_frequency: Optional[FrequencyFamily | float] = None,
    ) -> bool:
        """
        Update a chunk's amplitude and/or phase in place.

        The chunk must already exist (call surf_and_flag first to ingest it).
        If new_frequency is given, the chunk may be reassigned to a new group.

        Returns True if the chunk existed and was updated.
        """
        with self._lock:
            if chunk_id not in self._chunks:
                return False

            if new_amplitude is not None:
                self._amplitudes[chunk_id] = new_amplitude.astype(np.float32)

            if new_frequency is not None:
                new_phi = float(new_frequency)
                self._chunks[chunk_id].update_phase(new_phi)
                # Reassign group if phase family changed
                new_gid = self._phase_to_group_id(new_phi)
                old_gid = self._chunks[chunk_id].group_id
                if new_gid != old_gid:
                    self._ensure_group(new_gid, new_phi)
                    if old_gid and old_gid in self._groups:
                        self._groups[old_gid].member_ids.discard(chunk_id)
                        self._dirty_groups.add(old_gid)
                    self._groups[new_gid].member_ids.add(chunk_id)
                    self._dirty_groups.add(new_gid)
                    self._chunks[chunk_id].group_id = new_gid
                else:
                    # Same group but phase changed — centroid still needs refresh
                    self._dirty_groups.add(new_gid)

            return True

    # ── Inspection ────────────────────────────────────────────────────────

    def all_chunk_ids(self) -> List[str]:
        return list(self._chunks.keys())

    def chunk_co_activation_pairs(self) -> Dict[Tuple[str, str], int]:
        return dict(self._chunk_coact)

    def get_amplitude(self, chunk_id: str) -> Optional[np.ndarray]:
        return self._amplitudes.get(chunk_id)

    def chunk_count(self) -> int:
        return len(self._chunks)

    # ── Persistence ───────────────────────────────────────────────────────

    def save_state(self, path: str | Path = "resonance_state.db") -> None:
        """
        Flush in-RAM phase state to SQLite sidecar. WAL mode for concurrency.

        Amplitude vectors are NOT persisted here — they live in the source DB
        and are re-supplied by the caller at startup via surf_and_flag().
        Persisting them would double storage with no benefit.
        """
        with self._lock:
            db = sqlite3.connect(str(path))
            db.execute("PRAGMA journal_mode=WAL")
            db.executescript("""
                CREATE TABLE IF NOT EXISTS chunks (
                    chunk_id       TEXT PRIMARY KEY,
                    phi            REAL NOT NULL,
                    last_access    REAL NOT NULL,
                    phase_velocity REAL NOT NULL DEFAULT 0.0,
                    group_id       TEXT
                );
                CREATE TABLE IF NOT EXISTS chunk_coact (
                    id_a   TEXT NOT NULL,
                    id_b   TEXT NOT NULL,
                    weight INTEGER NOT NULL DEFAULT 1,
                    PRIMARY KEY (id_a, id_b)
                );
                CREATE TABLE IF NOT EXISTS groups (
                    group_id     TEXT PRIMARY KEY,
                    phi          REAL NOT NULL,
                    last_access  REAL NOT NULL,
                    group_vector BLOB
                );
                CREATE TABLE IF NOT EXISTS group_members (
                    group_id TEXT NOT NULL,
                    chunk_id TEXT NOT NULL,
                    PRIMARY KEY (group_id, chunk_id)
                );
            """)

            db.executemany(
                "INSERT OR REPLACE INTO chunks VALUES (?,?,?,?,?)",
                [(cid, m.phi, m.last_access, m.phase_velocity, m.group_id)
                 for cid, m in self._chunks.items()])

            db.executemany(
                "INSERT OR REPLACE INTO chunk_coact VALUES (?,?,?)",
                [(p[0], p[1], w) for p, w in self._chunk_coact.items()])

            db.executemany(
                "INSERT OR REPLACE INTO groups VALUES (?,?,?,?)",
                [(gid, g.phi, g.last_access,
                  g.group_vector.tobytes() if g.group_vector is not None else None)
                 for gid, g in self._groups.items()])

            db.executemany(
                "INSERT OR REPLACE INTO group_members VALUES (?,?)",
                [(gid, cid)
                 for gid, g in self._groups.items()
                 for cid in g.member_ids])

            db.commit()
            db.close()

    def load_state(self, path: str | Path = "resonance_state.db") -> None:
        """Re-hydrate RAM registry from sidecar file on boot."""
        p = Path(path)
        if not p.exists():
            return

        with self._lock:
            db = sqlite3.connect(str(p))
            db.row_factory = sqlite3.Row

            self._chunks.clear()
            self._recency_heap.clear()
            for row in db.execute("SELECT * FROM chunks"):
                m = ChunkMeta(
                    phi=row["phi"],
                    last_access=row["last_access"],
                    phase_velocity=row["phase_velocity"],
                    group_id=row["group_id"],
                )
                m._prev_phi = row["phi"]
                cid = row["chunk_id"]
                self._chunks[cid] = m
                heapq.heappush(self._recency_heap, (-m.last_access, cid))

            self._chunk_coact.clear()
            for row in db.execute("SELECT * FROM chunk_coact"):
                self._chunk_coact[(row["id_a"], row["id_b"])] = row["weight"]

            self._groups.clear()
            self._dirty_groups.clear()
            for row in db.execute("SELECT * FROM groups"):
                blob = row["group_vector"]
                vec  = np.frombuffer(blob, dtype=np.float32).copy() if blob else None
                self._groups[row["group_id"]] = GroupMeta(
                    group_id=row["group_id"],
                    phi=row["phi"],
                    last_access=row["last_access"],
                    group_vector=vec,
                )
            for row in db.execute("SELECT * FROM group_members"):
                grp = self._groups.get(row["group_id"])
                if grp:
                    grp.member_ids.add(row["chunk_id"])

            # Amplitudes are NOT stored in the sidecar.
            # The caller must re-supply them via surf_and_flag() or
            # by re-ingesting from the source DB after load_state().
            self._amplitudes.clear()

            db.close()

    def clear(self) -> None:
        """Wipe all in-memory state (does not touch disk)."""
        with self._lock:
            self._chunks.clear()
            self._groups.clear()
            self._chunk_coact.clear()
            self._amplitudes.clear()
            self._recency_heap.clear()
            self._dirty_groups.clear()
            self._active_phase = FrequencyFamily.NEUTRAL.value
